var align=["left","center","right","justify"],style=["bold","italic","underline"],textBody=document.querySelector(".text-body");function removeClasses(a,b){for(var c=document.querySelector(a),d=0;d<b.length;d++)c.classList.contains(b[d])&&c.classList.remove(b[d])}export function initTextEdit(){style.forEach(function(a){document.getElementById("".concat(a,"-btn")).addEventListener("click",function(){textBody.classList.toggle(a)})}),align.forEach(function(a){document.getElementById("".concat(a,"-btn")).addEventListener("click",function(){textBody.classList.toggle(a),removeClasses(".text-body",align.filter(function(b){return b!==a}))})}),document.getElementById("colorPicker").addEventListener("input",function(){textBody.style.color=this.value}),document.getElementById("fontSize").addEventListener("change",function(){textBody.style.fontSize=this.value/10+"rem"}),document.getElementById("fontFamily").addEventListener("change",function(){textBody.style.fontFamily=this.value}),document.getElementById("lineHeight").addEventListener("change",function(){textBody.style.lineHeight=this.value})}